import{_ as r,o as a,c as t,a2 as o}from"./chunks/framework.BWuWLRhz.js";const b=JSON.parse('{"title":"代理后的隐私保护","description":"DNS 泄露、WebRTC、浏览器指纹——代理连接之后仍需要注意的隐私事项。","frontmatter":{"description":"DNS 泄露、WebRTC、浏览器指纹——代理连接之后仍需要注意的隐私事项。"},"headers":[],"relativePath":"guide/privacy.md","filePath":"guide/privacy.md","lastUpdated":1783252730000}'),l={name:"guide/privacy.md"};function s(i,e,n,c,p,d){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="代理后的隐私保护" tabindex="-1">代理后的隐私保护 <a class="header-anchor" href="#代理后的隐私保护" aria-label="Permalink to &quot;代理后的隐私保护&quot;">​</a></h1><p>连接代理只是第一步。以下几个环节处理不当，你的真实网络信息仍可能暴露。</p><h2 id="dns-泄露" tabindex="-1">DNS 泄露 <a class="header-anchor" href="#dns-泄露" aria-label="Permalink to &quot;DNS 泄露&quot;">​</a></h2><p><strong>是什么</strong>：流量走了代理，但域名解析请求仍发给了本地运营商 DNS——对方就能看到你访问了哪些网站。</p><p><strong>怎么检测</strong>：连接代理后访问 <a href="https://browserleaks.com/dns" target="_blank" rel="noreferrer">browserleaks.com/dns</a>，如果结果里出现你所在地运营商的 DNS 服务器，说明存在泄露。</p><p><strong>怎么解决</strong>：</p><ul><li>Clash 系客户端（Clash Verge Rev / Clash Meta / Clash Mi）开启 <strong>TUN 模式</strong>，或在 DNS 设置中开启 <strong>DNS 劫持</strong></li><li>确保客户端模式为规则 / 全局，而不是仅设置了浏览器代理</li></ul><h2 id="webrtc-泄露" tabindex="-1">WebRTC 泄露 <a class="header-anchor" href="#webrtc-泄露" aria-label="Permalink to &quot;WebRTC 泄露&quot;">​</a></h2><p><strong>是什么</strong>：浏览器的 WebRTC 功能（视频通话等使用）可能绕过代理直接暴露本机 IP。</p><p><strong>怎么检测</strong>：访问 <a href="https://browserleaks.com/webrtc" target="_blank" rel="noreferrer">browserleaks.com/webrtc</a>，查看是否显示了你的真实公网 IP。</p><p><strong>怎么解决</strong>：</p><ul><li>客户端开启 <strong>TUN 模式</strong>（全局接管后 WebRTC 也走代理）</li><li>或在浏览器安装 WebRTC 限制插件 / 在 <code>about:config</code> 类设置中禁用 WebRTC</li></ul><h2 id="浏览器指纹与账号关联" tabindex="-1">浏览器指纹与账号关联 <a class="header-anchor" href="#浏览器指纹与账号关联" aria-label="Permalink to &quot;浏览器指纹与账号关联&quot;">​</a></h2><ul><li>长期登录的账号（Google 等）本身就标识了你，代理只改变网络位置</li><li>对隐私敏感的操作建议使用<strong>独立浏览器配置文件</strong>或隐私模式</li><li>时区 / 语言与节点地区差异过大可能触发某些网站的风控，属正常现象</li></ul><h2 id="使用习惯建议" tabindex="-1">使用习惯建议 <a class="header-anchor" href="#使用习惯建议" aria-label="Permalink to &quot;使用习惯建议&quot;">​</a></h2><ul><li><strong>不要公开订阅链接</strong>——它等同于你的账号使用权（详见<a href="./subscription">订阅说明</a>）</li><li>敏感账号开启两步验证，与代理无关但同样重要</li><li>客户端保持更新，旧版本可能存在已修复的安全问题</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>本站全中转节点 + 隧道加密，不记录用户访问内容。隐私政策全文见主站<a href="https://freedomport.cc/#/privacy-policy" target="_blank" rel="noreferrer">隐私政策</a>。</p></div>',17)])])}const g=r(l,[["render",s]]);export{b as __pageData,g as default};
